import{_ as e,o,c as i,ag as t}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"OAuth","description":"OpenClaw의 OAuth: 토큰 교환, 저장, 멀티 계정 패턴","frontmatter":{"title":"OAuth","description":"OpenClaw의 OAuth: 토큰 교환, 저장, 멀티 계정 패턴"},"headers":[],"relativePath":"concepts/oauth.md","filePath":"concepts/oauth.md","lastUpdated":null}'),l={name:"concepts/oauth.md"};function n(s,a,p,r,h,c){return o(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="oauth" tabindex="-1">OAuth <a class="header-anchor" href="#oauth" aria-label="Permalink to &quot;OAuth&quot;">​</a></h1><p>OpenClaw는 이를 제공하는 프로바이더 (특히 <strong>OpenAI Codex (ChatGPT OAuth)</strong>)에 대한 OAuth를 통한 &quot;구독 인증&quot;을 지원합니다. Anthropic의 경우, 현실적인 분리는 다음과 같습니다:</p><ul><li><strong>Anthropic API 키</strong>: 일반 Anthropic API 청구</li><li><strong>Anthropic Claude CLI / OpenClaw 내 구독 인증</strong>: Anthropic 직원이 이 사용이 다시 허용된다고 알려주었습니다</li></ul><p>OpenAI Codex OAuth는 OpenClaw와 같은 외부 도구에서의 사용을 위해 명시적으로 지원됩니다. 이 페이지는 다음을 설명합니다:</p><p>프로덕션에서 Anthropic의 경우, API 키 인증이 더 안전한 권장 경로입니다.</p><ul><li>OAuth <strong>토큰 교환</strong> 작동 방식 (PKCE)</li><li>토큰이 <strong>저장</strong>되는 위치 (및 이유)</li><li><strong>여러 계정</strong> 처리 방법 (프로필 + 세션별 오버라이드)</li></ul><p>OpenClaw는 자체 OAuth 또는 API 키 흐름을 제공하는 <strong>프로바이더 플러그인</strong>도 지원합니다. 다음을 통해 실행하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="토큰-싱크-존재하는-이유" tabindex="-1">토큰 싱크 (존재하는 이유) <a class="header-anchor" href="#토큰-싱크-존재하는-이유" aria-label="Permalink to &quot;토큰 싱크 (존재하는 이유)&quot;">​</a></h2><p>OAuth 프로바이더는 일반적으로 로그인/새로 고침 흐름 중에 <strong>새 리프레시 토큰</strong>을 발행합니다. 일부 프로바이더 (또는 OAuth 클라이언트)는 동일한 사용자/앱에 대해 새 토큰이 발행될 때 이전 리프레시 토큰을 무효화할 수 있습니다.</p><p>실제 증상:</p><ul><li>OpenClaw와 Claude Code / Codex CLI를 통해 로그인 → 나중에 무작위로 로그아웃됩니다</li></ul><p>이를 줄이기 위해 OpenClaw는 <code>auth-profiles.json</code>을 <strong>토큰 싱크</strong>로 처리합니다:</p><ul><li>런타임이 <strong>한 곳</strong>에서 자격 증명을 읽습니다</li><li>여러 프로필을 유지하고 결정론적으로 라우팅할 수 있습니다</li><li>Codex CLI와 같은 외부 CLI에서 자격 증명을 재사용할 때, OpenClaw는 출처와 함께 미러링하고 리프레시 토큰 자체를 순환하는 대신 해당 외부 소스를 다시 읽습니다</li></ul><h2 id="저장-토큰이-있는-위치" tabindex="-1">저장 (토큰이 있는 위치) <a class="header-anchor" href="#저장-토큰이-있는-위치" aria-label="Permalink to &quot;저장 (토큰이 있는 위치)&quot;">​</a></h2><p>시크릿은 <strong>에이전트별로</strong> 저장됩니다:</p><ul><li>인증 프로필 (OAuth + API 키 + 선택적 값 수준 참조): <code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth-profiles.json</code></li><li>레거시 호환성 파일: <code>~/.openclaw/agents/&lt;agentId&gt;/agent/auth.json</code> (발견 시 정적 <code>api_key</code> 항목이 제거됨)</li></ul><p>레거시 가져오기 전용 파일 (여전히 지원되지만 메인 저장소가 아님):</p><ul><li><code>~/.openclaw/credentials/oauth.json</code> (첫 사용 시 <code>auth-profiles.json</code>으로 가져옴)</li></ul><p>위의 모든 것은 <code>$OPENCLAW_STATE_DIR</code> (상태 디렉터리 오버라이드)도 지원합니다. 전체 참조: <a href="/openclaw-docs-ko/gateway/configuration-reference#auth-storage">/gateway/configuration</a></p><p>정적 시크릿 참조 및 런타임 스냅샷 활성화 동작은 <a href="/openclaw-docs-ko/gateway/secrets">시크릿 관리</a>를 참조하십시오.</p><h2 id="anthropic-레거시-토큰-호환성" tabindex="-1">Anthropic 레거시 토큰 호환성 <a class="header-anchor" href="#anthropic-레거시-토큰-호환성" aria-label="Permalink to &quot;Anthropic 레거시 토큰 호환성&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Anthropic의 공개 Claude Code 문서에 따르면 직접 Claude Code 사용은 Claude 구독 한도 내에 있으며, Anthropic 직원이 OpenClaw 스타일 Claude CLI 사용이 다시 허용된다고 알려주었습니다. 따라서 OpenClaw는 Anthropic이 새 정책을 게시하지 않는 한 Claude CLI 재사용 및 <code>claude -p</code> 사용을 이 통합에서 허가된 것으로 처리합니다.</p><p>Anthropic의 현재 직접 Claude Code 플랜 문서는 <a href="https://support.claude.com/en/articles/11145838-using-claude-code-with-your-pro-or-max-plan" target="_blank" rel="noreferrer">Pro 또는 Max 플랜으로 Claude Code 사용</a> 및 <a href="https://support.anthropic.com/en/articles/11845131-using-claude-code-with-your-team-or-enterprise-plan/" target="_blank" rel="noreferrer">Team 또는 Enterprise 플랜으로 Claude Code 사용</a>을 참조하십시오.</p><p>OpenClaw에서 다른 구독형 옵션을 원하면 <a href="/openclaw-docs-ko/providers/openai">OpenAI Codex</a>, <a href="/openclaw-docs-ko/providers/qwen">Qwen Cloud Coding Plan</a>, <a href="/openclaw-docs-ko/providers/minimax">MiniMax Coding Plan</a>, <a href="/openclaw-docs-ko/providers/glm">Z.AI / GLM Coding Plan</a>을 참조하십시오.</p></div><p>OpenClaw는 Anthropic 설정 토큰을 지원되는 토큰 인증 경로로도 노출하지만, 이제 가능한 경우 Claude CLI 재사용 및 <code>claude -p</code>를 선호합니다.</p><h2 id="anthropic-claude-cli-마이그레이션" tabindex="-1">Anthropic Claude CLI 마이그레이션 <a class="header-anchor" href="#anthropic-claude-cli-마이그레이션" aria-label="Permalink to &quot;Anthropic Claude CLI 마이그레이션&quot;">​</a></h2><p>OpenClaw는 Anthropic Claude CLI 재사용을 다시 지원합니다. 호스트에 로컬 Claude 로그인이 이미 있는 경우, 온보딩/구성이 직접 재사용할 수 있습니다.</p><h2 id="oauth-교환-로그인-작동-방식" tabindex="-1">OAuth 교환 (로그인 작동 방식) <a class="header-anchor" href="#oauth-교환-로그인-작동-방식" aria-label="Permalink to &quot;OAuth 교환 (로그인 작동 방식)&quot;">​</a></h2><p>OpenClaw의 대화형 로그인 흐름은 <code>@mariozechner/pi-ai</code>에 구현되어 마법사/커맨드에 연결됩니다.</p><h3 id="anthropic-설정-토큰" tabindex="-1">Anthropic 설정 토큰 <a class="header-anchor" href="#anthropic-설정-토큰" aria-label="Permalink to &quot;Anthropic 설정 토큰&quot;">​</a></h3><p>흐름 형태:</p><ol><li>OpenClaw에서 Anthropic 설정 토큰 또는 붙여넣기 토큰 시작</li><li>OpenClaw가 결과 Anthropic 자격 증명을 인증 프로필에 저장</li><li>모델 선택은 <code>anthropic/...</code>에 유지됨</li><li>기존 Anthropic 인증 프로필은 롤백/순서 제어에 계속 사용 가능</li></ol><h3 id="openai-codex-chatgpt-oauth" tabindex="-1">OpenAI Codex (ChatGPT OAuth) <a class="header-anchor" href="#openai-codex-chatgpt-oauth" aria-label="Permalink to &quot;OpenAI Codex (ChatGPT OAuth)&quot;">​</a></h3><p>OpenAI Codex OAuth는 OpenClaw 워크플로를 포함하여 Codex CLI 외부에서의 사용을 위해 명시적으로 지원됩니다.</p><p>흐름 형태 (PKCE):</p><ol><li>PKCE verifier/challenge + 랜덤 <code>state</code> 생성</li><li><code>https://auth.openai.com/oauth/authorize?...</code> 열기</li><li><code>http://127.0.0.1:1455/auth/callback</code>에서 콜백 캡처 시도</li><li>콜백을 바인딩할 수 없는 경우 (또는 원격/헤드리스인 경우), 리디렉션 URL/코드 붙여넣기</li><li><code>https://auth.openai.com/oauth/token</code>에서 교환</li><li>액세스 토큰에서 <code>accountId</code> 추출 및 <code>{ access, refresh, expires, accountId }</code> 저장</li></ol><p>마법사 경로는 <code>openclaw onboard</code> → 인증 선택 <code>openai-codex</code>입니다.</p><h2 id="새로-고침-만료" tabindex="-1">새로 고침 + 만료 <a class="header-anchor" href="#새로-고침-만료" aria-label="Permalink to &quot;새로 고침 + 만료&quot;">​</a></h2><p>프로필은 <code>expires</code> 타임스탬프를 저장합니다.</p><p>런타임에서:</p><ul><li><code>expires</code>가 미래인 경우 → 저장된 액세스 토큰 사용</li><li>만료된 경우 → 새로 고침 (파일 잠금 아래) 및 저장된 자격 증명 덮어쓰기</li><li>예외: 재사용된 외부 CLI 자격 증명은 외부에서 관리됩니다. OpenClaw는 CLI 인증 저장소를 다시 읽고 복사된 리프레시 토큰 자체를 사용하지 않습니다</li></ul><p>새로 고침 흐름은 자동입니다. 일반적으로 토큰을 수동으로 관리할 필요가 없습니다.</p><h2 id="여러-계정-프로필-라우팅" tabindex="-1">여러 계정 (프로필) + 라우팅 <a class="header-anchor" href="#여러-계정-프로필-라우팅" aria-label="Permalink to &quot;여러 계정 (프로필) + 라우팅&quot;">​</a></h2><p>두 가지 패턴:</p><h3 id="_1-권장-별도-에이전트" tabindex="-1">1) 권장: 별도 에이전트 <a class="header-anchor" href="#_1-권장-별도-에이전트" aria-label="Permalink to &quot;1) 권장: 별도 에이전트&quot;">​</a></h3><p>&quot;personal&quot;과 &quot;work&quot;가 절대 상호작용하지 않기를 원한다면, 격리된 에이전트 (별도 세션 + 자격 증명 + 워크스페이스)를 사용하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agents</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> personal</span></span></code></pre></div><p>그런 다음 에이전트별로 인증을 구성하고 (마법사) 올바른 에이전트로 채팅을 라우팅하십시오.</p><h3 id="_2-고급-하나의-에이전트에서-여러-프로필" tabindex="-1">2) 고급: 하나의 에이전트에서 여러 프로필 <a class="header-anchor" href="#_2-고급-하나의-에이전트에서-여러-프로필" aria-label="Permalink to &quot;2) 고급: 하나의 에이전트에서 여러 프로필&quot;">​</a></h3><p><code>auth-profiles.json</code>은 동일한 프로바이더에 대한 여러 프로필 ID를 지원합니다.</p><p>사용할 프로필 선택:</p><ul><li>구성 순서를 통해 전역으로 (<code>auth.order</code>)</li><li><code>/model ...@&lt;profileId&gt;</code>를 통해 세션별로</li></ul><p>예시 (세션 오버라이드):</p><ul><li><code>/model Opus@anthropic:work</code></li></ul><p>기존 프로필 ID를 확인하는 방법:</p><ul><li><code>openclaw channels list --json</code> (<code>auth[]</code> 표시)</li></ul><p>관련 문서:</p><ul><li><a href="/openclaw-docs-ko/concepts/model-failover">/concepts/model-failover</a> (순환 + 쿨다운 규칙)</li><li><a href="/openclaw-docs-ko/tools/slash-commands">/tools/slash-commands</a> (커맨드 표면)</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/gateway/authentication">인증</a> — 모델 프로바이더 인증 개요</li><li><a href="/openclaw-docs-ko/gateway/secrets">시크릿</a> — 자격 증명 저장 및 SecretRef</li><li><a href="/openclaw-docs-ko/gateway/configuration-reference#auth-storage">구성 참조</a> — 인증 구성 키</li></ul>`,59)])])}const C=e(l,[["render",n]]);export{u as __pageData,C as default};
